import "std/array"
import "std/math"

func is_prime(n: Int64): Bool {
    if n <= 1 {
        return false
    }
    if n == 2 {
        return true
    }
    if n % 2 == 0 {
        return false
    }
    let sqrt_n = math.sqrt(n)
    var i: Int64 = 3
    while i <= sqrt_n {
        if n % i == 0 {
            return false
        }
        i += 2
    }
    return true
}

func solve(nums: Array<Int64>): Int64 {
    let n = array.len(nums)
    if n == 1 {
        return 0
    }

    var prime_indices = dict<Int64, Array<Int64>>()
    for i in 0..n {
        let num = nums[i]
        if is_prime(num) {
            if not dict.has(prime_indices, num) {
                dict.set(prime_indices, num, array.empty())
            }
            dict.get(prime_indices, num).append(i)
        }
    }

    var divisible_indices = dict<Int64, Array<Int64>>()
    for i in 0..n {
        let num = nums[i]
        for p in dict.keys(prime_indices) {
            if num % p == 0 {
                if not dict.has(divisible_indices, p) {
                    dict.set(divisible_indices, p, array.empty())
                }
                dict.get(divisible_indices, p).append(i)
            }
        }
    }

    var visited = array.fill(n, false)
    var queue = array.empty()
    queue.append(0)
    visited[0] = true
    var steps: Int64 = 0

    while not array.empty(queue) {
        let size = array.len(queue)
        for _ in 0..size {
            let current = queue.pop_front()
            if current == n - 1 {
                return steps
            }

            let next = current + 1
            if next < n and not visited[next] {
                visited[next] = true
                queue.append(next)
            }

            let prev = current - 1
            if prev >= 0 and not visited[prev] {
                visited[prev] = true
                queue.append(prev)
            }

            let num = nums[current]
            if is_prime(num) {
                for j in dict.get(divisible_indices, num, array.empty()) {
                    if j != current and not visited[j] {
                        visited[j] = true
                        queue.append(j)
                    }
                }
            }
        }
        steps += 1
    }

    return -1
}
